// main.js
const { ipcMain, dialog } = require('electron');

// 渲染过来：选文件（示例）
ipcMain.handle('dialog:openFile', async () => {
  const { canceled, filePaths } = await dialog.showOpenDialog({
    properties: ['openFile'],
  });
  if (canceled) return null;
  return filePaths[0]; // 只回路径，勿暴露整个 fs
});

// 渲染过来：设备相关意图（示意，真外设放主进程驱动）
ipcMain.handle('device:scan', async (_event, payload) => {
  if (!payload || typeof payload.type !== 'string') {
    throw new Error('invalid payload');
  }
  // return await scanHardware(payload.type);
  return { ok: true, type: payload.type };
});

// preload.js
const { contextBridge, ipcRenderer } = require('electron');

contextBridge.exposeInMainWorld('api', {
  openFile: () => ipcRenderer.invoke('dialog:openFile'),
  scan: (type) => ipcRenderer.invoke('device:scan', { type }),
  // 主 → 渲染：订阅时返回取消函数，避免泄漏
  onUpdateProgress: (cb) => {
    const listener = (_e, data) => cb(data);
    ipcRenderer.on('update:progress', listener);
    return () => ipcRenderer.removeListener('update:progress', listener);
  },
});

// renderer（Vue/React 里）
async function onPickFile() {
  const filePath = await window.api.openFile();
  if (filePath) console.log('picked', filePath);
}

async function onScan() {
  const res = await window.api.scan('barcode');
  console.log(res);
}

