// main.js — electron-updater 示意
const { autoUpdater } = require('electron-updater');
const { BrowserWindow, ipcMain } = require('electron');

autoUpdater.autoDownload = false; // 先询用户或业务空闲再下

function setupAutoUpdate() {
  autoUpdater.checkForUpdates();

  autoUpdater.on('update-available', (info) => {
    // 通知渲染：有新版本
    BrowserWindow.getAllWindows()[0]?.webContents.send('update:available', info);
  });

  autoUpdater.on('download-progress', (p) => {
    BrowserWindow.getAllWindows()[0]?.webContents.send('update:progress', {
      percent: p.percent,
    });
  });

  autoUpdater.on('update-downloaded', () => {
    BrowserWindow.getAllWindows()[0]?.webContents.send('update:downloaded');
  });

  autoUpdater.on('error', (err) => {
    BrowserWindow.getAllWindows()[0]?.webContents.send('update:error', String(err));
  });
}

ipcMain.handle('update:startDownload', async () => {
  await autoUpdater.downloadUpdate();
});

ipcMain.handle('update:quitAndInstall', () => {
  autoUpdater.quitAndInstall(); // 退出并安装已下载包
});
